#nullable enable // autogenerated

using MVZ2Logic;
using MVZ2Logic.Definitions;
using MVZ2Logic.Options;

namespace MVZ2.GameContent.Options
{
    [AutoOptionWidgetDefinition(LogicOptionWidgetNames.showSponsorNames)]
    public class ShowSponsorsOptionToggle : OptionToggleDefinition
    {
        public ShowSponsorsOptionToggle(string nsp, string name) : base(nsp, name)
        {
        }
        public override bool GetValue(IOptionContext context)
        {
            return Global.Options.GetOptionBool(LogicOptionItemID.showSponsorNames);
        }

        public override void OnValueChanged(IOptionContext context, bool value)
        {
            Global.Options.SetOptionBool(LogicOptionItemID.showSponsorNames, value);
            Global.Options.SaveOptions();
        }
    }
}
